## Return Values

**Return values** let functions send data back to you. Use the `return` keyword.

```javascript
function multiply(x, y) {
  return x * y;
}

let result = multiply(4, 5);  // result is now 20
console.log(result);
```

blocks.code:
function calculateArea(width, height) {
  return width * height;
}

let area1 = calculateArea(5, 10);
let area2 = calculateArea(7, 3);

console.log('Area 1:', area1);  // 50
console.log('Area 2:', area2);  // 21

function getGrade(score) {
  if (score >= 90) return 'A';
  if (score >= 80) return 'B';
  if (score >= 70) return 'C';
  if (score >= 60) return 'D';
  return 'F';
}

console.log('Score 95:', getGrade(95));  // A
console.log('Score 75:', getGrade(75));  // C
console.log('Score 55:', getGrade(55));  // F
